// ModernSpaceCard integrates with SpaceDetailPanel via SpaceCardContainer
// Relevant props: space, usersInSpace, isSelected
// Space object has: space.capacity (number)
// usersInSpace.length gives current occupancy

// Calculate capacity percentage for styling:
const capacityPercentage = space.capacity 
  ? (usersInSpace.length / space.capacity) * 100 
  : 0;
const isFull = space.capacity && usersInSpace.length >= space.capacity;
const isNearingFull = capacityPercentage >= 80 && capacityPercentage < 100;

// Current beacon usage in component:
const beaconState = useAttentionBeacon(
  space.id,
  usersInSpace,
  space.capacity || 0,
  spaceBeaconData
);

// Current Join button implementation:
<Button
  variant="default"
  size="sm"
  className="..."
  onClick={(e) => {
    e.stopPropagation();
    onJoin?.();
  }}
  data-space-action="true"
>
  <LogIn className="h-4 w-4 mr-1" />
  Join
</Button>

// Add isFull prop to component:
interface SpaceActionButtonsProps {
  // ... existing props
  isFull?: boolean; // NEW: Disable join when true
}

// Modify Join button:
<Button
  variant="default"
  size="sm"
  className={cn("...", isFull && "opacity-50 cursor-not-allowed")}
  onClick={(e) => {
    e.stopPropagation();
    if (!isFull) onJoin?.();
  }}
  disabled={isFull}
  title={isFull ? "Space is full - cannot join" : undefined}
  aria-disabled={isFull}
  data-space-action="true"
>
  <LogIn className="h-4 w-4 mr-1" />
  Join
</Button>

// CapacityIndicator already exists with color-coded display
// Shows current/capacity with tooltip for utilization %
// Colors: low (green), medium (amber), high (red)
// Consider extending with:
// - showBar prop for progress bar
// - theme-aware token colors
// - aria-live for real-time updates

// Current occupancy trigger (>80%):
if (capacity > 0) {
  const occupancyRatio = usersInSpace.length / capacity;
  if (occupancyRatio > opts.occupancyThreshold) {
    active = true;
    severity = 'normal';
    reason = 'High occupancy';
    return { active, severity, reason };
  }
}

// Story 3.12 Enhancement:
// - Change reason to "Space nearing capacity" for clarity
// - Add 100% capacity trigger with different reason
// - Keep severity as 'normal' for 80-99%
// - Consider 'info' severity for 100% (full) state

// Existing capacity tokens:
capacityIndicator: {
  container: "flex items-center gap-1 text-xs text-muted-foreground",
  icon: {
    base: "h-3.5 w-3.5",
    low: "text-emerald-500",  // <33% full
    medium: "text-amber-500", // 33-66% full
    high: "text-rose-500"     // >66% full
  }
}

