// POST /api/spaces/[id]/join
import { NextResponse } from 'next/server';
import { createSupabaseServerClient } from '@/lib/supabase/server-client';

export async function POST(
  request: Request, 
  { params }: { params: Promise<{ id: string }> }
) {
  const { id: spaceId } = await params;
  const supabase = await createSupabaseServerClient();

  // 1. Get current user
  const { data: { user }, error: authError } = await supabase.auth.getUser();
  if (authError || !user) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }

  // 2. Get space with capacity
  const { data: space, error: spaceError } = await supabase
    .from('spaces')
    .select('id, capacity')
    .eq('id', spaceId)
    .single();

  if (spaceError || !space) {
    return NextResponse.json({ error: 'Space not found' }, { status: 404 });
  }

  // 3. Get current occupancy
  const { count: currentOccupancy } = await supabase
    .from('users')
    .select('id', { count: 'exact', head: true })
    .eq('current_space_id', spaceId);

  // 4. Check capacity
  if (space.capacity && currentOccupancy >= space.capacity) {
    return NextResponse.json(
      { error: 'Space is full', code: 'SPACE_FULL' },
      { status: 409 }
    );
  }

  // 5. Update user's current_space_id
  const { error: updateError } = await supabase
    .from('users')
    .update({ current_space_id: spaceId })
    .eq('supabase_uid', user.id);

  if (updateError) {
    return NextResponse.json(
      { error: 'Failed to join space' },
      { status: 500 }
    );
  }

  return NextResponse.json({ success: true, spaceId });
}

