// src/components/floor-plan/modern/FullBadge.tsx
import React from 'react';
import { cn } from '@/lib/utils';

interface FullBadgeProps {
  className?: string;
}

export const FullBadge: React.FC<FullBadgeProps> = ({ className }) => {
  return (
    <span
      className={cn(
        // Base styles
        'inline-flex items-center px-2 py-0.5 text-xs font-semibold rounded',
        // Theme-aware colors via CSS variables
        'bg-[var(--vo-full-badge-bg)] text-[var(--vo-full-badge-text)]',
        // Animation
        'animate-in fade-in duration-200',
        className
      )}
      aria-label="Space is full"
      role="status"
    >
      Full
    </span>
  );
};

export default FullBadge;
